mapper.select:
select count(1)
from payment_refund_order ro
where ro.tenant_id = #{tenantId}

  and ro.status = #{status}



where ro.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and ro.id = #{id}
limit 1



where ro.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and bo.app_code = #{appId}
  and ro.biz_refund_no = #{bizRefundNo}
limit 1



where ro.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and ro.refund_order_no = #{refundOrderNo}
limit 1



where ro.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and ro.channel_refund_no = #{channelRefundNo}
limit 1

select coalesce(sum(ro.refund_amount), 0)
from payment_refund_order ro
where ro.tenant_id = #{tenantId}
  and ro.payment_order_id = #{paymentOrderId}
  and ro.status in ('CREATED', 'REFUNDING', 'PROCESSING', 'SUCCESS')

select flow_no
from payment_transaction_flow
where tenant_id = #{tenantId}
  and refund_order_id = #{refundOrderId}
order by created_at desc
limit 1

select ro.id, ro.refund_order_no as refundOrderNo, ro.biz_refund_no as bizRefundNo, ro.payment_order_id as paymentOrderId, ro.channel_refund_no as channelRefundNo, ro.refund_amount as refundAmount, ro.reason, ro.status, ro.refund_time as refundTime, ro.tenant_id as tenantId, ro.created_by as createdBy, ro.created_at as createdAt, ro.updated_by as updatedBy, ro.updated_at as updatedAt from payment_refund_order ro join payment_order po on po.id = ro.payment_order_id and po.tenant_id = ro.tenant_id where ro.tenant_id = #{tenantId} and po.channel_code = #{channelCode} and ro.status = 'SUCCESS' and ro.channel_refund_no is not null and ro.refund_time >= #{billDate} and ro.refund_time < #{nextBillDate}
and ro.channel_refund_no not in
#{channelRefundNo}
order by ro.refund_time asc, ro.channel_refund_no asc
